class AwsS3Service {
  final String accessKey;
  final String secretKey;
  final String region;
  final String bucket;

  AwsS3Service({
    required this.accessKey,
    required this.secretKey,
    required this.region,
    required this.bucket,
  });

  Future<String> uploadBytes({
    required Uint8List bytes,
    required String fileName,
    required String contentType,
  }) async {
    final now = DateTime.now().toUtc();
    final amzDate = _formatAmzDate(now);
    final dateStamp = _formatDate(now);
    final safeName = fileName.replaceAll(RegExp(r'[^A-Za-z0-9._-]'), '_');
    final objectKey = 'uploads/${dateStamp}_${Random().nextInt(1 << 32)}_$safeName';
    final host = '$bucket.s3.$region.amazonaws.com';
    final uri = Uri.https(host, '/$objectKey');

    final payloadHash = sha256.convert(bytes).toString();
    final canonicalHeaders =
        'content-type:$contentType\nhost:$host\nx-amz-content-sha256:$payloadHash\nx-amz-date:$amzDate\n';
    final signedHeaders = 'content-type;host;x-amz-content-sha256;x-amz-date';
    final canonicalRequest = [
      'PUT',
      '/$objectKey',
      '',
      canonicalHeaders,
      signedHeaders,
      payloadHash,
    ].join('\n');

    final credentialScope = '$dateStamp/$region/s3/aws4_request';
    final stringToSign = [
      'AWS4-HMAC-SHA256',
      amzDate,
      credentialScope,
      sha256.convert(utf8.encode(canonicalRequest)).toString(),
    ].join('\n');

    final signingKey = _getSignatureKey(secretKey, dateStamp, region, 's3');
    final signature = _bytesToHex(_hmacSha256(signingKey, stringToSign));

    final authorizationHeader =
        'AWS4-HMAC-SHA256 Credential=$accessKey/$credentialScope, SignedHeaders=$signedHeaders, Signature=$signature';

    final response = await http.put(
      uri,
      headers: {
        'Content-Type': contentType,
        'Host': host,
        'x-amz-content-sha256': payloadHash,
        'x-amz-date': amzDate,
        'Authorization': authorizationHeader,
      },
      body: bytes,
    );

    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw Exception('S3 upload failed: ${response.statusCode} ${response.body}');
    }

    return uri.toString();
  }

  String _formatAmzDate(DateTime dt) {
    return '${_formatDate(dt)}T${dt.hour.toString().padLeft(2, '0')}${dt.minute.toString().padLeft(2, '0')}${dt.second.toString().padLeft(2, '0')}Z';
  }

  String _formatDate(DateTime dt) {
    return '${dt.year.toString().padLeft(4, '0')}${dt.month.toString().padLeft(2, '0')}${dt.day.toString().padLeft(2, '0')}';
  }

  List<int> _getSignatureKey(String key, String dateStamp, String regionName, String serviceName) {
    final kDate = _hmacSha256(utf8.encode('AWS4$key'), dateStamp);
    final kRegion = _hmacSha256(kDate, regionName);
    final kService = _hmacSha256(kRegion, serviceName);
    final kSigning = _hmacSha256(kService, 'aws4_request');
    return kSigning;
  }

  List<int> _hmacSha256(List<int> key, String data) {
    final hmac = Hmac(sha256, key);
    return hmac.convert(utf8.encode(data)).bytes;
  }

  String _bytesToHex(List<int> bytes) {
    final buffer = StringBuffer();
    for (final b in bytes) {
      buffer.write(b.toRadixString(16).padLeft(2, '0'));
    }
    return buffer.toString();
  }
}

class GoogleVisionService {
  final String apiKey;

  GoogleVisionService({required this.apiKey});

  Future<String> analyzeImage(Uint8List bytes) async {
    final uri = Uri.parse('https://vision.googleapis.com/v1/images:annotate?key=$apiKey');

    final body = {
      'requests': [
        {
          'image': {
            'content': base64Encode(bytes),
          },
          'features': [
            {'type': 'LABEL_DETECTION', 'maxResults': 8},
            {'type': 'TEXT_DETECTION', 'maxResults': 5},
            {'type': 'IMAGE_PROPERTIES', 'maxResults': 5},
            {'type': 'SAFE_SEARCH_DETECTION', 'maxResults': 5},
          ],
        }
      ]
    };

    final response = await http.post(
      uri,
      headers: {'Content-Type': 'application/json'},
      body: jsonEncode(body),
    );

    if (response.statusCode < 200 || response.statusCode >= 300) {
      throw Exception('Vision API failed: ${response.statusCode} ${response.body}');
    }

    final decoded = jsonDecode(response.body) as Map<String, dynamic>;
    final responses = decoded['responses'] as List<dynamic>? ?? [];
    if (responses.isEmpty) return 'No analysis returned.';

    final result = responses.first as Map<String, dynamic>;
    final buffer = StringBuffer();

    final labels = result['labelAnnotations'] as List<dynamic>? ?? [];
    if (labels.isNotEmpty) {
      buffer.writeln('Labels:');
      for (final item in labels) {
        final m = item as Map<String, dynamic>;
        buffer.writeln('- ${m['description']} (${((m['score'] ?? 0.0) as num).toStringAsFixed(2)})');
      }
      buffer.writeln();
    }

    final textAnnotations = result['textAnnotations'] as List<dynamic>? ?? [];
    if (textAnnotations.isNotEmpty) {
      final first = textAnnotations.first as Map<String, dynamic>;
      buffer.writeln('Detected Text:');
      buffer.writeln(first['description'] ?? '');
      buffer.writeln();
    }

    final safe = result['safeSearchAnnotation'] as Map<String, dynamic>?;
    if (safe != null) {
      buffer.writeln('Safe Search:');
      for (final key in ['adult', 'spoof', 'medical', 'violence', 'racy']) {
        if (safe.containsKey(key)) {
          buffer.writeln('- $key: ${safe[key]}');
        }
      }
      buffer.writeln();
    }

    final props = result['imagePropertiesAnnotation'] as Map<String, dynamic>?;
    final colors = props?['dominantColors']?['colors'] as List<dynamic>? ?? [];
    if (colors.isNotEmpty) {
      buffer.writeln('Dominant Colors:');
      for (final c in colors.take(5)) {
        final m = c as Map<String, dynamic>;
        final color = m['color'] as Map<String, dynamic>? ?? {};
        buffer.writeln(
          '- rgb(${color['red'] ?? 0}, ${color['green'] ?? 0}, ${color['blue'] ?? 0}) score=${((m['score'] ?? 0.0) as num).toStringAsFixed(2)}',
        );
      }
    }

    final output = buffer.toString().trim();
    return output.isEmpty ? 'Analysis completed, but no readable annotations were returned.' : output;
  }
}